// Data source: static JSON generated by scripts/build_site_data.py
const DATA_URL = 'static/data/papers.json';

let allPapers = [];    // raw experiment entries
let groupedPapers = []; // grouped by DOI

// ---------------------------------------------------------------------------
// Init
// ---------------------------------------------------------------------------
document.addEventListener('DOMContentLoaded', async () => {
  const res = await fetch(DATA_URL);
  allPapers = await res.json();
  groupedPapers = groupByDoi(allPapers);
  renderPaperList(groupedPapers);

  document.getElementById('searchInput').addEventListener('input', filterPapers);
  document.getElementById('journalFilter').addEventListener('change', filterPapers);
});

// ---------------------------------------------------------------------------
// Group experiments by DOI into papers
// ---------------------------------------------------------------------------
function groupByDoi(papers) {
  const map = {};
  papers.forEach(p => {
    if (!map[p.doi]) {
      // Use the base title (strip " — Experiment Name" suffixes)
      const baseTitle = p.title.replace(/ \u2014 .*$/, '');
      map[p.doi] = {
        doi: p.doi,
        title: baseTitle,
        authors: p.authors,
        journal: p.journal,
        year: p.year,
        replication_url: p.replication_url,
        experiments: [],
      };
    }
    map[p.doi].experiments.push(p);
  });
  return Object.values(map);
}

// ---------------------------------------------------------------------------
// Filtering
// ---------------------------------------------------------------------------
function filterPapers() {
  const query = document.getElementById('searchInput').value.toLowerCase();
  const journal = document.getElementById('journalFilter').value;

  let papers = groupedPapers;
  if (journal) papers = papers.filter(p => p.journal === journal);
  if (query) {
    papers = papers.filter(p =>
      p.title.toLowerCase().includes(query) ||
      p.authors.join(' ').toLowerCase().includes(query) ||
      p.experiments.some(e => e.description.toLowerCase().includes(query))
    );
  }
  renderPaperList(papers);
}

// ---------------------------------------------------------------------------
// Paper list (one card per paper)
// ---------------------------------------------------------------------------
function renderPaperList(papers) {
  const container = document.getElementById('paper-list');
  document.getElementById('paper-detail').classList.add('hidden');
  container.classList.remove('hidden');

  if (!papers.length) {
    container.innerHTML = '<p style="color:#888">No papers found.</p>';
    return;
  }

  container.innerHTML = papers.map(p => {
    const numExp = p.experiments.length;
    const numReplicated = p.experiments.filter(e => e.has_results).length;
    const allReplicated = numReplicated === numExp;
    const noneReplicated = numReplicated === 0;

    return `
      <div class="paper-card" onclick="showPaperByDoi('${p.doi}')">
        <div class="title">${p.title}</div>
        <div class="meta">
          <span class="journal">${p.journal}</span>
          ${p.authors.join(', ')} (${p.year})
          &middot; <a href="https://doi.org/${p.doi}" target="_blank" onclick="event.stopPropagation()">DOI</a>
          &middot; ${numExp} experiment${numExp > 1 ? 's' : ''}
        </div>
        <div class="description">${p.experiments[0].description}</div>
        <span class="status ${allReplicated ? 'replicated' : (noneReplicated ? 'pending' : 'partial')}">
          ${allReplicated ? 'Replicated' : (noneReplicated ? 'Pending' : `${numReplicated}/${numExp} Replicated`)}
        </span>
      </div>
    `;
  }).join('');
}

// ---------------------------------------------------------------------------
// Paper detail (grouped by DOI, shows experiments)
// ---------------------------------------------------------------------------
function showPaperByDoi(doi) {
  const group = groupedPapers.find(p => p.doi === doi);
  if (!group) return;

  document.getElementById('paper-list').classList.add('hidden');
  const detail = document.getElementById('paper-detail');
  detail.classList.remove('hidden');

  const experiments = group.experiments;

  detail.innerHTML = `
    <span class="back-link" onclick="goBack()">&larr; Back to papers</span>

    <div class="detail-header">
      <h2>${group.title}</h2>
      <div class="meta">
        <span class="journal" style="display:inline-block;background:#eef2ff;color:#3730a3;padding:0.1rem 0.45rem;border-radius:4px;font-weight:600;font-size:0.8rem;margin-right:0.4rem">${group.journal}</span>
        ${group.authors.join(', ')} (${group.year})
        &middot; <a href="https://doi.org/${group.doi}" target="_blank">DOI</a>
        ${group.replication_url ? `&middot; <a href="${group.replication_url}" target="_blank">Replication data</a>` : ''}
      </div>
    </div>

    ${experiments.length > 1 ? `
    <div class="experiment-list">
      <div class="experiment-list-label">Experiments</div>
      ${experiments.map((exp, i) => {
        const expLabel = exp.title.includes('\u2014') ? exp.title.split('\u2014').pop().trim() : exp.title;
        return `
        <div class="experiment-card ${i === 0 ? 'active' : ''}" onclick="showExperiment('${exp.id}', this)">
          <div class="experiment-card-number">Experiment ${i + 1}</div>
          <div class="experiment-card-title">${expLabel}</div>
          <span class="status ${exp.has_results ? 'replicated' : 'pending'}">
            ${exp.has_results ? 'Replicated' : 'Pending'}
          </span>
        </div>
      `}).join('')}
    </div>
    ` : ''}

    <div id="experiment-detail">
      ${renderExperiment(experiments[0])}
    </div>
  `;

  window._experiments = experiments;
}

function showExperiment(expId, el) {
  const exp = window._experiments.find(e => e.id === expId);
  if (!exp) return;
  document.querySelectorAll('.experiment-card').forEach(c => c.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('experiment-detail').innerHTML = renderExperiment(exp);
}

function renderExperiment(paper) {
  const hasComps = paper.comparisons && paper.comparisons.length > 0;
  window._comparisons = paper.comparisons || [];

  return `
    <div class="detail-section">
      <h3>Experiment Design</h3>
      <p>${paper.description}</p>
    </div>

    <div class="detail-section">
      <h3>Original Results</h3>
      ${renderOriginalResults(paper.original_results)}
    </div>

    ${hasComps ? `
      <div class="detail-section">
        <h3>Replication Results</h3>
        ${renderModelTabs(paper.comparisons)}
        <div id="comparison-content">
          ${renderComparison(paper.comparisons[0])}
        </div>
      </div>
    ` : `
      <div class="detail-section">
        <h3>Replication Results</h3>
        <p style="color:#888">No replication results yet.</p>
      </div>
    `}
  `;
}

function goBack() {
  document.getElementById('paper-detail').classList.add('hidden');
  document.getElementById('paper-list').classList.remove('hidden');
}

// ---------------------------------------------------------------------------
// Original results
// ---------------------------------------------------------------------------
function renderOriginalResults(results) {
  if (!results) return '<p style="color:#888">No original results available.</p>';

  const rows = Object.entries(results).map(([condition, stats]) => `
    <tr>
      <td>${formatCondition(condition)}</td>
      <td class="num">${stats.mean.toFixed(4)}</td>
      <td class="num">${stats.se.toFixed(4)}</td>
      <td class="num">${stats.n}</td>
    </tr>
  `).join('');

  return `
    <table class="results-table">
      <thead>
        <tr><th>Condition</th><th class="num">Mean</th><th class="num">SE</th><th class="num">N</th></tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  `;
}

// ---------------------------------------------------------------------------
// Comparison rendering (per model)
// ---------------------------------------------------------------------------
function renderModelTabs(comparisons) {
  if (comparisons.length <= 1) return '';
  return `
    <div class="model-tabs">
      ${comparisons.map((c, i) => `
        <button class="model-tab ${i === 0 ? 'active' : ''}"
                onclick="switchModel(${i})">${c.model}</button>
      `).join('')}
    </div>
  `;
}

function switchModel(idx) {
  document.querySelectorAll('.model-tab').forEach((tab, i) => {
    tab.classList.toggle('active', i === idx);
  });
  document.getElementById('comparison-content').innerHTML =
    renderComparison(window._comparisons[idx]);
}

function renderComparison(comp) {
  const conditions = comp.conditions;
  const modelName = comp.model;

  // Table
  const rows = conditions.map(c => {
    const pval = parseFloat(c.p_value);
    const isSig = pval < 0.05;
    return `
      <tr>
        <td>${formatCondition(c.condition)}</td>
        <td class="num">${fmtNum(c.original_mean)}</td>
        <td class="num">${fmtNum(c.replicated_mean)}</td>
        <td class="num">${fmtNum(c.delta)}</td>
        <td class="num">${fmtNum(c.z_stat)}</td>
        <td class="num ${isSig ? 'sig' : 'ns'}">${fmtNum(c.p_value)}${isSig ? ' *' : ''}</td>
      </tr>
    `;
  }).join('');

  const table = `
    <p style="font-size:0.85rem;color:#555;margin-bottom:0.5rem">Model: <strong>${modelName}</strong></p>
    <table class="results-table">
      <thead>
        <tr>
          <th>Condition</th>
          <th class="num">Original Mean</th>
          <th class="num">Replicated Mean</th>
          <th class="num">Delta</th>
          <th class="num">z-stat</th>
          <th class="num">p-value</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
    <p style="font-size:0.78rem;color:#888;margin-top:0.5rem">
      * p &lt; 0.05 indicates the replicated mean differs significantly from the original.
      Non-significant = closer replication.
    </p>
  `;

  // Bar chart
  const maxVal = Math.max(
    ...conditions.map(c => Math.max(parseFloat(c.original_mean), parseFloat(c.replicated_mean)))
  ) * 1.2;

  const bars = conditions.map(c => {
    const origH = (parseFloat(c.original_mean) / maxVal) * 140;
    const repH = (parseFloat(c.replicated_mean) / maxVal) * 140;
    return `
      <div class="bar-group">
        <div class="bar-pair">
          <div class="bar original" style="height:${origH}px">
            <span class="bar-value">$${fmtNum(c.original_mean)}</span>
          </div>
          <div class="bar replicated" style="height:${repH}px">
            <span class="bar-value">$${fmtNum(c.replicated_mean)}</span>
          </div>
        </div>
        <div class="bar-label">${formatCondition(c.condition)}</div>
      </div>
    `;
  }).join('');

  const chart = `
    <div class="chart-legend">
      <span class="leg-original">Original</span>
      <span class="leg-replicated">Replicated (${modelName})</span>
    </div>
    <div class="bar-chart">${bars}</div>
  `;

  return chart + table;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
function formatCondition(name) {
  return String(name)
    .replace(/_/g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase());
}

function fmtNum(val) {
  const n = parseFloat(val);
  if (isNaN(n)) return val;
  return n.toFixed(4);
}
